//! # San Francisco Bridge — Topological Landmark
//!
//! Generates a synthetic 3D manifold of the Golden Gate Bridge.
//! Expresses the bridge as a sequence of architectural voxels.
//!
//! Projects the "SF Handshake" as a Pleromatic Frame.

use distributed_inference::app_streaming::{AppState, HolographicAppBridge};
use distributed_inference::holographic_reconstruction::VoxelCoord;
use std::collections::HashMap;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!(" [ GENERATING SAN FRANCISCO LANDMARK: GOLDEN GATE BRIDGE ] ");

    let mut bridge_voxels = Vec::new();

    // 1. South Tower (x=10, y=20)
    for z in 5..35 {
        bridge_voxels.push(VoxelCoord { x: 10, y: 20, z });
        bridge_voxels.push(VoxelCoord { x: 11, y: 20, z });
    }

    // 2. North Tower (x=30, y=20)
    for z in 5..35 {
        bridge_voxels.push(VoxelCoord { x: 30, y: 20, z });
        bridge_voxels.push(VoxelCoord { x: 31, y: 20, z });
    }

    // 3. Main Span (Parabola between towers at z=25)
    for x in 10..31 {
        let x_f = x as f32;
        // Parabola: z = (x-20)^2 / 8 + 20
        let z = ((x_f - 20.0).powi(2) / 8.0 + 20.0) as i32;
        bridge_voxels.push(VoxelCoord { x, y: 20, z });
        bridge_voxels.push(VoxelCoord { x, y: 21, z });
    }

    println!(" Generated Bridge: {} voxels", bridge_voxels.len());

    // 4. Bundle into AppState
    let state = AppState {
        app_id: "sf-bridge".into(),
        components: HashMap::from([
            ("location".into(), "San Francisco".into()),
            ("landmark".into(), "Golden Gate Bridge".into()),
        ]),
        active_coords: bridge_voxels,
    };

    // 5. Emit Pleromatic Frame
    let mut bridge = HolographicAppBridge::new("sf-node-1");
    let frame = bridge.capture_frame(&state, vec![]); // No logic path for now, just the shape

    println!(" [ EMITTING SF HANDSHAKE ] ");
    println!(" Frame Source: {}", frame.source_id);
    println!(" Data Size: {} bytes", frame.data.len());

    // In a live environment, this would be broadcast to the Aeon Monitor.
    // For now, we save it as a local artifact for the monitor to ingest.
    let path = "sf_handshake.frame";
    std::fs::write(path, bincode::serialize(&frame)?)?;
    println!(" Saved Handshake to: {}", path);

    Ok(())
}
